function minTotalCost(n, roads, appleCost, k) {
    const graph = Array.from({ length: n + 1 }, () => []);
    for (const [u, v, cost] of roads) {
        graph[u].push([v, cost]);
        graph[v].push([u, cost]);
    }

    const answer = Array(n).fill(0);
    for (let start = 1; start <= n; start++) {
        const pq = [[0, start]];
        const dist = Array(n + 1).fill(Infinity);
        dist[start] = 0;

        while (pq.length) {
            const [d, u] = pq.shift();
            if (d > dist[u]) continue;

            for (const [v, cost] of graph[u]) {
                const c = d + cost + (u !== start ? cost * k : 0) + appleCost[v - 1];
                if (c < dist[v]) {
                    dist[v] = c;
                    pq.push([c, v]);
                    pq.sort((a, b) => a[0] - b[0]);
                }
            }
        }

        answer[start - 1] = dist[start];
    }
    return answer;
}
